import React, { useState } from 'react';
import './style.css';
//import ReactDOM from 'react-dom/client';
//import reportWebVitals from './reportWebVitals';
function SelectOption({index,exercise,duration,updatedValue}){
    return(
        <>
            <label htmlFor={`exercise-${index}`} >Add an Exercise</label>
            <select value={exercise} id={`exercise-${index}`} onChange={(e)=>{updatedValue(index,"exercise",e.target.value)}}>
                <option value="select">--Select Type--</option>
                <option value="walk">Walking</option>
                <option value="Jogging">Jogging</option>
                <option value="skipping">Skipping</option>
                <option value="yoga">Yoga</option>
                <option value="sports">Sports</option>
                <option value="meditation">Meditation</option>
                <option value="cycling">Cycling</option>
                <option value="hiking">Hiking</option>
                <option value="dancing">Dancing</option>
                <option value="swimming">Swimming</option>
            </select>
            <input value={duration} id={`duration-${index}`} placeholder='Duration(min)' type='text' onChange={(e)=>{updatedValue(index,"duration",e.target.value)}}></input>
        </>
    );
}



function SelectExercise(){
    const [selectedExercise,setSelectedExercise]=useState([{exercise:"",duration:""}]);
    function updateExercise(index,field,value){
        const updated=[...selectedExercise];
        updated[index][field]=value;
        setSelectedExercise(updated);
    }
    function addExercise(){
        setSelectedExercise([...selectedExercise,{exercise:"",duration:""}]);
    }
    function submitExercisee(e){
        e.preventDefault();
        console.log(selectedExercise);
    }
    return(
        <>
            <h1>Welcome to exercise Tracking Page</h1>
            <form onSubmit={submitExercisee}>
                {selectedExercise.map((item,index)=>(
                    <SelectOption 
                    key={index}
                    index={index}
                    exercise={item.exercise}
                    duration={item.duration}
                    updatedValue={updateExercise}/>
                ))}
                <button type='button' onClick={addExercise}>Add Exercise</button>
                <input type='submit' value='submit all'/>
            </form>
        </>
    );
}


export default SelectExercise;
